func TestInjectMetaPrompt(t *testing.T) {
	tests := []struct {
		name          string
		existingFile  string
		promptPath    string
		promptContent string
		expectError   bool
		expectContent string
	}{
		{
			name:          "inject into new file",
			existingFile:  "",
			promptPath:    "claude/system-prompts/test.md",
			promptContent: "# Test Prompt\nContent here",
			expectError:   false,
